<?php declare(strict_types=1);
namespace App\Services;
final class HealthMonitor { public function snapshot(?array $stream):array { $disk=disk_free_space(dirname(__DIR__,2));$total=disk_total_space(dirname(__DIR__,2));$process=$this->process((int)($stream['pid']??0));return ['stream'=>$stream,'disk_free_bytes'=>$disk?:0,'disk_used_percent'=>$total?round((1-($disk/$total))*100,1):0,'load_average'=>sys_getloadavg()[0]??null,'process'=>$process,'checked_at'=>gmdate('c')]; } private function process(int $pid):array { if($pid<1||!is_dir('/proc/'.$pid))return ['running'=>false];$status=(string)file_get_contents('/proc/'.$pid.'/status');preg_match('/VmRSS:\s+(\d+)/',$status,$rss);return ['running'=>true,'pid'=>$pid,'memory_bytes'=>isset($rss[1])?(int)$rss[1]*1024:null]; } }
